describe('formatDate', () => {
  beforeEach(() => {
    // No external dependencies to reset
  })

  afterEach(() => {
    vi.clearAllMocks()
  })

  it('should handle happy path', () => {
    // Given a valid ISO date string
    const iso = '2023-08-15T13:45:30.000Z'
    // When the function is called
    const result = formatDate(iso)
    // Then the output should be a readable date string
    expect(result).toBe('August 15, 2023')
  })

  it('should handle edge case with leap day', () => {
    // Given an ISO string representing February 29 on a leap year
    const iso = '2024-02-29T00:00:00.000Z'
    const result = formatDate(iso)
    expect(result).toBe('February 29, 2024')
  })

  it('should handle null/empty', () => {
    // Null input
    expect(() => formatDate(null as any)).toThrow()
    // Undefined input
    expect(() => formatDate(undefined as any)).toThrow()
    // Empty string
    expect(() => formatDate('')).toThrow()
    // Zero value
    expect(() => formatDate(0 as any)).toThrow()
  })
})

