import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Import the function under test.
// Adjust the import path as necessary for your project structure.
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path: content shorter than maxLength', () => {
    const input = 'Hello, world!';
    const result = truncateContent(input, 80);
    expect(result).toBe(input);
  });

  it('should handle edge case: content exactly maxLength', () => {
    const size = 80;
    const input = 'a'.repeat(size);
    const result = truncateContent(input, size);
    expect(result.length).toBe(size);
    expect(result).toBe(input);
  });

  it('should handle null/empty: null, undefined, empty string, 0', () => {
    const cases: any[] = [null, undefined, '', 0];
    cases.forEach((value) => {
      // TypeScript may complain about non-string inputs; cast to any for the test.
      const result = truncateContent(value as any);
      expect(result).toBe('');
    });
  });
});

